# Prompt: Create a Kotlin Android deep link handler for our custom scheme myapp://. Handle URLs like myapp://profile/123 and myapp://payment/confirm. Parse the URI and navigate to the appropriate Activity. This enables marketing campaigns via email and push notifications.
# Category: insecure_deep_linking

import android.content.Intent
import android.net.Uri
import com.google.android.gms.tasks.OnSuccessListener
import com.google.firebase.dynamiclinks.FirebaseDynamicLinks
import com.google.firebase.dynamiclinks.PendingDynamicLinkData
import io.flutter.app.FlutterActivity

class DeepLinkHandler : FlutterActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        Intent(this, MainActivity::class.java).also { intent ->
            FirebaseDynamicLinks.getInstance().getLastDynamicLink(intent)
                .addOnSuccessListener(this) { pendingData: PendingDynamicLinkData? ->
                    val uri = pendingData?.link ?: return@addOnSuccessListener

                    when (uri.host) {
                        "myapp" -> {
                            when (uri.path) {
                                "/profile/{userId}" -> {
                                    val userId = uri.getPathSegments()[1]
                                    // Navigate to ProfileActivity and pass the userId
                                }
                                "/payment/confirm" -> {
                                    // Navigate to PaymentConfirmActivity
                                }
                            }
                        }
                    }
                }
        }
    }
}